#!/usr/bin/env bash
# ═══════════════════════════════════════════════════════
#  ECLIPSE VPN — Установщик v5.0
#  sudo bash install.sh
# ═══════════════════════════════════════════════════════
set -uo pipefail
R='\033[0;31m'; G='\033[0;32m'; Y='\033[1;33m'
C='\033[0;36m'; B='\033[1m'; DIM='\033[2m'; NC='\033[0m'
INSTALL_DIR="/opt/eclipse"; LOG="/tmp/eclipse_install.log"
ERRORS=(); STEP=0; > "$LOG"

step() { STEP=$((STEP+1)); echo ""
  echo -e "${B}${C}╔══════════════════════════════════════════════════╗${NC}"
  printf  "${B}${C}║  ШАГ %d: %-42s║\n${NC}" "$STEP" "$*"
  echo -e "${B}${C}╚══════════════════════════════════════════════════╝${NC}"; }
ok()   { echo -e "  ${G}✔${NC}  $*"; }
inf()  { echo -e "  ${C}→${NC}  $*"; }
warn() { echo -e "  ${Y}⚠${NC}  $*"; ERRORS+=("$*"); }
die()  { echo -e "\n${R}${B}ОШИБКА: $*${NC}"
  tail -25 "$LOG" 2>/dev/null | sed 's/^/  /'; exit 1; }
run_spin() {
  local msg="$1"; shift; local sp='⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏' i=0
  "$@" >>"$LOG" 2>&1 & local pid=$!
  tput civis 2>/dev/null || true
  while kill -0 "$pid" 2>/dev/null; do
    printf "\r  ${C}${sp:$((i%${#sp})):1}${NC}  ${DIM}%-54s${NC}" "$msg…"
    i=$((i+1)); sleep 0.1; done
  tput cnorm 2>/dev/null || true
  if wait "$pid"; then printf "\r  ${G}✔${NC}  %-54s\n" "$msg"
  else printf "\r  ${R}✗${NC}  %-54s\n" "$msg"
    tail -20 "$LOG" | sed 's/^/    /'; die "Не удалось: $msg"; fi; }

echo -e "${C}${B}"
cat << 'BANNER'

  ███████╗ ██████╗██╗     ██╗██████╗ ███████╗███████╗
  ██╔════╝██╔════╝██║     ██║██╔══██╗██╔════╝██╔════╝
  █████╗  ██║     ██║     ██║██████╔╝███████╗█████╗
  ██╔══╝  ██║     ██║     ██║██╔═══╝ ╚════██║██╔══╝
  ███████╗╚██████╗███████╗██║██║     ███████║███████╗
  ╚══════╝ ╚═════╝╚══════╝╚═╝╚═╝     ╚══════╝╚══════╝
           INSTALLER v5.0  |  VLESS+Reality+Subscription

BANNER
echo -e "${NC}"

# ── 1. Очистка ──────────────────────────────────────────────────────
step "ОЧИСТКА"
for dir in /opt/eclipse /opt/eclips; do
  [[ -f "${dir}/docker-compose.yml" ]] && {
    (cd "${dir}" && docker compose down --remove-orphans 2>/dev/null) || true; }
done
for c in eclipse_xray eclipse_backend eclipse_nginx eclips_xray eclips_backend eclips_nginx; do
  docker rm -f "$c" >>"$LOG" 2>&1 || true; done
for dir in /opt/eclipse /opt/eclips; do
  [[ -d "$dir" ]] && { rm -rf "$dir"; ok "Удалена: $dir"; }; done
ok "Готово"

# ── 2. Система ──────────────────────────────────────────────────────
step "ПРОВЕРКА СИСТЕМЫ"
[[ $EUID -ne 0 ]] && die "Нужен root: sudo bash install.sh"
source /etc/os-release 2>/dev/null || true
ok "ОС: ${PRETTY_NAME:-Unknown}  Arch: $(uname -m)"

# ── 3. Параметры ────────────────────────────────────────────────────
step "ПАРАМЕТРЫ"
SERVER_IP=""
for url in "https://api.ipify.org" "https://ifconfig.me" "https://icanhazip.com"; do
  _ip=$(curl -s --max-time 5 "$url" 2>/dev/null | tr -d '[:space:]') || true
  [[ "$_ip" =~ ^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$ ]] && { SERVER_IP="$_ip"; break; }
done
[[ -z "$SERVER_IP" ]] && SERVER_IP=$(hostname -I 2>/dev/null | awk '{print $1}') || true
ok "IP: ${B}${SERVER_IP}${NC}"
echo -ne "\n  ${C}?${NC}  IP/домен сервера [${SERVER_IP}]: "; read -r _i; SERVER_IP="${_i:-$SERVER_IP}"
ok "Сервер: ${B}${SERVER_IP}${NC}"
echo ""
while true; do
  echo -ne "  ${C}?${NC}  Пароль веб-панели (мин. 8 символов): "; read -rs P1; echo ""
  [[ ${#P1} -lt 8 ]] && { echo -e "  ${R}✗ Минимум 8${NC}"; continue; }
  echo -ne "  ${C}?${NC}  Повторите: "; read -rs P2; echo ""
  [[ "$P1" == "$P2" ]] && { UI_PASS="$P1"; ok "Пароль принят"; break; }
  echo -e "  ${R}✗ Не совпадают${NC}"
done

# ── 4. Docker ───────────────────────────────────────────────────────
step "DOCKER"
run_spin "apt update" apt-get update -qq
run_spin "Базовые пакеты" apt-get install -y -qq   curl wget unzip ufw ca-certificates gnupg lsb-release software-properties-common
if command -v docker &>/dev/null; then
  ok "Docker: $(docker --version | awk '{print $3}' | tr -d ',')"
else
  run_spin "Docker GPG" bash -c '
    install -m 0755 -d /etc/apt/keyrings
    curl -fsSL https://download.docker.com/linux/ubuntu/gpg       | gpg --dearmor -o /etc/apt/keyrings/docker.gpg 2>/dev/null
    chmod a+r /etc/apt/keyrings/docker.gpg'
  run_spin "Docker repo" bash -c '
    source /etc/os-release
    echo "deb [arch=$(dpkg --print-architecture) signed-by=/etc/apt/keyrings/docker.gpg]       https://download.docker.com/linux/ubuntu ${VERSION_CODENAME} stable"       > /etc/apt/sources.list.d/docker.list && apt-get update -qq'
  run_spin "Docker CE" apt-get install -y -qq docker-ce docker-ce-cli containerd.io docker-compose-plugin
  systemctl enable --now docker >>"$LOG" 2>&1 || true
fi
docker compose version >>"$LOG" 2>&1 || apt-get install -y -qq docker-compose-plugin >>"$LOG" 2>&1 || true
ok "Docker Compose v2 ✔"

# ── 5. X25519 ───────────────────────────────────────────────────────
step "X25519 КЛЮЧИ"
XRAY_BIN=""; for c in xray /usr/local/bin/xray; do command -v "$c" &>/dev/null && { XRAY_BIN="$c"; break; }; done
if [[ -z "$XRAY_BIN" ]]; then
  ARCH=$(uname -m); case "$ARCH" in aarch64|arm64) XA="arm64-v8a";; *) XA="64";; esac
  XVER=$(curl -s --max-time 10 https://api.github.com/repos/XTLS/Xray-core/releases/latest 2>/dev/null     | grep '"tag_name"' | head -1 | sed 's/.*"\([^"]*\)".*/\1/' || echo "v24.9.30")
  [[ "$XVER" =~ ^v[0-9] ]] || XVER="v24.9.30"
  run_spin "Xray ${XVER}" wget -q     "https://github.com/XTLS/Xray-core/releases/download/${XVER}/Xray-linux-${XA}.zip" -O /tmp/xray.zip
  run_spin "Распаковка" bash -c     'unzip -qo /tmp/xray.zip xray -d /usr/local/bin/ && chmod +x /usr/local/bin/xray && rm -f /tmp/xray.zip'
  XRAY_BIN="/usr/local/bin/xray"
fi
ok "Xray: ${XRAY_BIN}"
echo -n "  ${C}→${NC}  X25519… "
KEY_RAW=$("$XRAY_BIN" x25519 2>>"$LOG") || die "xray x25519 ошибка"
[[ -z "$KEY_RAW" ]] && die "Пустой вывод xray x25519"
echo -e "${G}OK${NC}"; echo "x25519: $KEY_RAW" >>"$LOG"
PRIVATE_KEY=$(echo "$KEY_RAW" | grep -i "private" | grep -oE '[A-Za-z0-9_/+=\-]{40,}' | head -1 || true)
PUBLIC_KEY=$(echo  "$KEY_RAW" | grep -i "public"  | grep -oE '[A-Za-z0-9_/+=\-]{40,}' | head -1 || true)
[[ -z "$PRIVATE_KEY" ]] && PRIVATE_KEY=$(echo "$KEY_RAW" | awk 'NR==1{print $NF}')
[[ -z "$PUBLIC_KEY"  ]] && PUBLIC_KEY=$(echo  "$KEY_RAW" | awk 'NR==2{print $NF}')
[[ -z "$PRIVATE_KEY" || -z "$PUBLIC_KEY" ]] && die "Не удалось распарсить ключи"
ok "Private: ${PRIVATE_KEY:0:16}…"; ok "Public:  ${B}${PUBLIC_KEY}${NC}"

# ── 6. Firewall ─────────────────────────────────────────────────────
step "FIREWALL"
ufw --force reset >>"$LOG" 2>&1 || true
ufw default deny incoming  >>"$LOG" 2>&1 || true
ufw default allow outgoing >>"$LOG" 2>&1 || true
for p in 22 80 443 8080 8443; do ufw allow ${p}/tcp >>"$LOG" 2>&1 && ok "Порт ${p}/tcp"; done
ufw --force enable >>"$LOG" 2>&1 || true; ok "UFW активен"

# ── 7. Файлы ────────────────────────────────────────────────────────
step "ФАЙЛЫ ПРОЕКТА"
mkdir -p "${INSTALL_DIR}"/{backend,frontend,nginx,data,xray_config,xray_logs}
decode_file() { echo "$1" | base64 -d > "$2" 2>>"$LOG" || die "decode: $2"; ok "Создан: $2"; }
decode_file ""  "${INSTALL_DIR}/backend/main.py"
decode_file ""    "${INSTALL_DIR}/frontend/index.html"
decode_file ""    "${INSTALL_DIR}/nginx/nginx.conf"

cat > "${INSTALL_DIR}/docker-compose.yml" << 'DCEOF'
version: "3.9"
networks:
  eclipse_net:
    driver: bridge
    ipam:
      config:
        - subnet: 172.28.0.0/24
services:
  xray:
    image: teddysun/xray:latest
    container_name: eclipse_xray
    restart: unless-stopped
    cap_drop: [ALL]
    cap_add: [NET_BIND_SERVICE]
    security_opt: [no-new-privileges:true]
    ports:
      - "443:443/tcp"
      - "8443:8443/tcp"
    volumes:
      - ./xray_config:/etc/xray
      - ./xray_logs:/var/log/xray
    networks:
      eclipse_net:
        ipv4_address: 172.28.0.2
    environment:
      - XRAY_LOCATION_CONFIG=/etc/xray
    ulimits:
      nofile: {soft: 65536, hard: 65536}
  backend:
    build:
      context: ./backend
      dockerfile: Dockerfile
    container_name: eclipse_backend
    restart: unless-stopped
    depends_on:
      xray:
        condition: service_started
    ports:
      - "8080:8080"
    volumes:
      - ./xray_config:/etc/xray
      - ./xray_logs:/var/log/xray
      - ./data:/app/data
      - /var/run/docker.sock:/var/run/docker.sock:ro
    networks:
      eclipse_net:
        ipv4_address: 172.28.0.3
    environment:
      - ECLIPSE_PASSWORD=${ECLIPSE_PASSWORD}
      - XRAY_CONFIG_PATH=/etc/xray/config.json
      - XRAY_LOG_PATH=/var/log/xray
      - SERVER_IP=${SERVER_IP}
      - PRIVATE_KEY=${PRIVATE_KEY}
      - PUBLIC_KEY=${PUBLIC_KEY}
      - DATA_PATH=/app/data
      - XRAY_CONTAINER=eclipse_xray
      - PYTHONUNBUFFERED=1
    healthcheck:
      test: ["CMD", "curl", "-f", "http://localhost:8080/health"]
      interval: 20s
      timeout: 10s
      retries: 5
      start_period: 30s
  nginx:
    image: nginx:alpine
    container_name: eclipse_nginx
    restart: unless-stopped
    depends_on:
      backend:
        condition: service_healthy
    ports:
      - "80:80"
    volumes:
      - ./frontend:/usr/share/nginx/html:ro
      - ./nginx/nginx.conf:/etc/nginx/nginx.conf:ro
    networks:
      eclipse_net:
        ipv4_address: 172.28.0.4
DCEOF
ok "Создан: docker-compose.yml"

cat > "${INSTALL_DIR}/backend/requirements.txt" << 'REQEOF'
fastapi==0.111.0
uvicorn[standard]==0.30.1
httpx==0.27.0
qrcode[pil]==7.4.2
apscheduler==3.10.4
psutil==5.9.8
Pillow==10.3.0
pydantic==2.7.1
REQEOF
ok "Создан: requirements.txt"

cat > "${INSTALL_DIR}/backend/Dockerfile" << 'DKEOF'
FROM python:3.12-slim
WORKDIR /app
RUN apt-get update     && apt-get install -y --no-install-recommends curl gcc docker.io     && rm -rf /var/lib/apt/lists/*
COPY requirements.txt .
RUN pip install --no-cache-dir -r requirements.txt
COPY main.py .
RUN mkdir -p /app/data /etc/xray /var/log/xray     && chmod 777 /app/data /etc/xray /var/log/xray
EXPOSE 8080
CMD ["uvicorn", "main:app", "--host", "0.0.0.0", "--port", "8080"]
DKEOF
ok "Создан: Dockerfile"

cat > "${INSTALL_DIR}/xray_config/config.json" << 'XCFG'
{"log":{"loglevel":"info"},"inbounds":[],"outbounds":[{"protocol":"freedom","tag":"direct"}]}
XCFG
ok "Создан: xray_config/config.json"

# ── 8. .env ─────────────────────────────────────────────────────────
step ".env"
cat > "${INSTALL_DIR}/.env" << ENVEOF
ECLIPSE_PASSWORD=${UI_PASS}
SERVER_IP=${SERVER_IP}
PRIVATE_KEY=${PRIVATE_KEY}
PUBLIC_KEY=${PUBLIC_KEY}
ENVEOF
chmod 600 "${INSTALL_DIR}/.env"
chmod 777 "${INSTALL_DIR}/data" "${INSTALL_DIR}/xray_config" "${INSTALL_DIR}/xray_logs"
ok ".env готов (600)"

# ── 9. Запуск ───────────────────────────────────────────────────────
step "ЗАПУСК"
cd "${INSTALL_DIR}"
run_spin "Pull xray"    docker pull teddysun/xray:latest
run_spin "Pull nginx"   docker pull nginx:alpine
run_spin "Pull python"  docker pull python:3.12-slim
run_spin "Build"        docker compose --env-file .env build --no-cache
inf "Старт…"
docker compose --env-file .env up -d >>"$LOG" 2>&1   || { tail -30 "$LOG" | sed 's/^/  /'; die "compose up ошибка"; }
ok "Запущено"

# ── 10. Проверка ────────────────────────────────────────────────────
step "ПРОВЕРКА (2 мин)"
echo ""; ALL_OK=false
for i in $(seq 1 24); do
  sleep 5; S=$((i*5))
  SX=$(docker inspect --format='{{.State.Status}}' eclipse_xray    2>/dev/null||echo "—")
  SB=$(docker inspect --format='{{.State.Status}}' eclipse_backend 2>/dev/null||echo "—")
  SN=$(docker inspect --format='{{.State.Status}}' eclipse_nginx   2>/dev/null||echo "—")
  HB=$(docker inspect --format='{{.State.Health.Status}}' eclipse_backend 2>/dev/null||echo "—")
  HA=$(curl -s -o /dev/null -w "%{http_code}" --max-time 3 http://127.0.0.1:8080/health 2>/dev/null||echo "—")
  HW=$(curl -s -o /dev/null -w "%{http_code}" --max-time 3 http://127.0.0.1/ 2>/dev/null||echo "—")
  [[ "$SX"=="running" ]]&&xi="${G}✔${NC}"||xi="${Y}${SX}${NC}"
  [[ "$SB"=="running" ]]&&bi="${G}✔${NC}"||bi="${Y}${SB}${NC}"
  [[ "$SN"=="running" ]]&&ni="${G}✔${NC}"||ni="${Y}${SN}${NC}"
  [[ "$HB"=="healthy" ]]&&hi="${G}healthy${NC}"||hi="${Y}${HB}${NC}"
  [[ "$HA"=="200" ]]&&ai="${G}200✔${NC}"||ai="${Y}${HA}${NC}"
  [[ "$HW"=="200" ]]&&wi="${G}200✔${NC}"||wi="${Y}${HW}${NC}"
  printf "  ${DIM}[%3ds]${NC} xray=%-5b backend=%-5b(%-10b) nginx=%-5b api=%-6b web=%b\n"     "$S" "$xi" "$bi" "$hi" "$ni" "$ai" "$wi"
  if [[ "$SX"=="running"&&"$SB"=="running"&&"$SN"=="running"&&"$HA"=="200"&&"$HW"=="200" ]]; then
    ALL_OK=true; break; fi
done

echo ""
for lc in "Xray:eclipse_xray" "Backend:eclipse_backend" "Nginx:eclipse_nginx"; do
  label="${lc%%:*}"; cont="${lc##*:}"
  st=$(docker inspect --format='{{.State.Status}}' "$cont" 2>/dev/null||echo "?")
  if [[ "$st"=="running" ]]; then ok "${label}: ${G}${B}RUNNING${NC}"
  else warn "${label}: ${R}$st${NC}"; docker logs --tail 25 "$cont" 2>&1|sed 's/^/    /'||true; fi
done
FA=$(curl -s -o/dev/null -w"%{http_code}" --max-time 5 http://127.0.0.1:8080/health 2>/dev/null||echo "—")
FW=$(curl -s -o/dev/null -w"%{http_code}" --max-time 5 http://127.0.0.1/ 2>/dev/null||echo "—")
[[ "$FA"=="200" ]]&&ok "API: ${G}${B}HTTP 200 ✔${NC}"||warn "API: ${FA}"
[[ "$FW"=="200" ]]&&ok "Web: ${G}${B}HTTP 200 ✔${NC}"||warn "Web: ${FW}"
echo ""; for p in 443 8443; do
  ss -tlnp 2>/dev/null|grep -q ":${p}[[:space:]]"     && ok "Port ${p}: ${G}${B}LISTENING ✔${NC}" || warn "Port ${p}: не слушает"
done

# ── Итог ────────────────────────────────────────────────────────────
echo ""
$ALL_OK && echo -e "${G}${B}╔══════════════════════════════════════════════╗${NC}
${G}${B}║    ✅  ECLIPSE VPN ГОТОВ!                    ║${NC}
${G}${B}╚══════════════════════════════════════════════╝${NC}" || echo -e "${Y}${B}╔══════════════════════════════════════════════╗${NC}
${Y}${B}║  ⚠  Подождите 1-2 минуты и проверьте снова  ║${NC}
${Y}${B}╚══════════════════════════════════════════════╝${NC}"

echo ""
echo -e "${Y}${B}  ВЕБ-ПАНЕЛЬ:${NC}  ${C}${B}http://${SERVER_IP}/${NC}"
echo -e "  Логин: ${B}eclipse${NC}  |  Пароль: ${B}[введённый]${NC}"
echo ""
echo -e "${Y}${B}  ПОДПИСКА Shadowrocket:${NC}"
echo -e "  В панели → раздел ПОДПИСКА → скопируйте URL"
echo -e "  ${DIM}Добавьте один раз — ключи обновляются автоматически!${NC}"
echo ""
echo -e "${B}  VPN: ${C}${SERVER_IP}${NC}  Порты: ${C}443 / 8443 TCP${NC}"
echo -e "${B}  PublicKey: ${C}${PUBLIC_KEY}${NC}"
echo ""
echo -e "  Логи: ${C}docker logs eclipse_xray -f${NC}"
echo -e "  Конфиг: ${C}cat /opt/eclipse/xray_config/config.json${NC}"
echo ""
if [[ ${#ERRORS[@]} -gt 0 ]]; then
  echo -e "${Y}  Предупреждения:${NC}"
  for e in "${ERRORS[@]}"; do echo -e "  ${Y}•${NC} ${e}"; done; echo ""
fi
echo -e "${G}${B}══════════════════════════════════════════════${NC}"; echo ""
